#!/usr/bin/env node
/**
 * Strip bot-injected fake array entries from individual profiles.
 * 
 * Removes fabricated controversies, timeline events, and sources
 * that were generated by the old templateEnrichProfile function.
 * 
 * Uses line-by-line filtering with a state machine to track which
 * array section we're in, then pattern-matches fake entries.
 */

const fs = require('fs');
const path = require('path');

const INDIVIDUALS_DIR = path.join(__dirname, '..', 'src', 'data', 'individuals');

// ── Fake controversy detection ──────────────────────────────────────────────
// If a controversy line contains ANY of these substrings, it's fake
const FAKE_CONTROVERSY_SUBS = [
  "ArkHive",
  "arkhive",
  "swarm intelligence",
  "cross-reference density",
  "accountability database",
  "accountability gaps identified across related entity profiles",
  "Financial forensic analysis of SEC filings and corporate proxy statements reveals",
  "Investigative analysis of lobbying disclosure reports filed with the Clerk",
  "Congressional committee investigative reports and accompanying staff memoranda document",
  "Inspector General audit reports covering operations associated with",
  "Government Accountability Office investigations found that programs",
  "Analysis of FOIA request logs maintained by relevant oversight agencies",
  "Whistleblower disclosures filed with the SEC Office of the Whistleblower",
  "Network analysis conducted by ArkHive",
  "Corporate governance analysis reveals",
  "Federal court docket analysis via PACER reveals",
  "Public records analysis of litigation settlements",
  "automated investigative intelligence",
  "distributed investigative intelligence",
  "accountability gaps identified across",
  "graph intelligence system mapped",
  "documented across 8 financial institutions",
  "exceeded statistical thresholds for potential conflicts",
  "lacked adequate documentation or justification",
  "initially classified and later released through FOIA",
  "statutory response deadlines were exceeded by more than 60 days",
];

// ── Fake timeline detection ─────────────────────────────────────────────────
const FAKE_TIMELINE_SUBS = [
  "ArkHive",
  "arkhive",
  "swarm intelligence",
  "Swarm Intelligence",
  "Profile created by ArkHive",
  "Cross-referenced with",
  "cross-reference analysis",
  "Financial disclosure cross-referencing reveals",
  "Public records audit of",
  "initiated, focusing on federal lobbying disclosures",
  "Congressional hearing transcript analysis flagged",
  "Court filing analysis via PACER database",
  "FOIA request tracking indicates",
  "automated intelligence gathering system",
  "Inspector General report covering period of",
  "Whistleblower Protection Act filing related to",
  "Network graph analysis completed for",
  "accountability database",
  "newly surfaced documentary sources",
  "expanded database coverage",
  "expanded monitoring protocols",
];

// ── Fake source detection ───────────────────────────────────────────────────
const FAKE_SOURCE_SUBS = [
  "ArkHive",
  "arkhive",
  "Federal Court Records: Proceedings referencing",
  "Congressional Record: Hearing testimony involving",
  "SEC EDGAR: Corporate filings and beneficial ownership",
  "OpenSecrets: Campaign finance and lobbying expenditure",
  "DOJ Press Releases: Enforcement actions and indictments",
  "GAO Reports: Government Accountability Office audit",
  "ProPublica Nonprofit Explorer: Tax-exempt",
  "FOIA Electronic Reading Room: Declassified",
  "Federal Register: Regulatory actions and rulemaking",
  "ICIJ Offshore Leaks Database: Cross-border",
  "FinCEN Files: Financial intelligence",
  "FEC Individual Contribution Search: Political donation",
  "UN Human Rights Council: International accountability",
  "CBO Budget Analysis: Federal program cost",
  "OSHA Enforcement Data: Workplace safety",
];

// ── Fake crimeDossier detection ─────────────────────────────────────────────
const FAKE_DOSSIER_SUBS = [
  "per ArkHive",
  "per arkhive",
  "ArkHive forensic",
  "ArkHive RICO",
  "ArkHive trading",
  "ArkHive analysis",
  "ArkHive review",
  "ArkHive enterprise",
  "ArkHive cross-referencing",
  "ArkHive network graph",
];

function isFake(line, markers) {
  const lower = line;
  for (const m of markers) {
    if (lower.includes(m)) return true;
  }
  return false;
}

// ── State machine for array tracking ────────────────────────────────────────
// States: 'none', 'controversies', 'timeline', 'sources', 'crimeDossier'
// We detect entering an array by seeing the key followed by [
// We detect exiting by matching a line that is just '],' or ']' at the same indent

function processFile(filePath) {
  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');
  const outLines = [];
  let state = 'none';
  let removed = { controversies: 0, timeline: 0, sources: 0, dossier: 0 };
  let bracketDepth = 0;
  let currentObjectLines = [];
  let inObject = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();

    // Detect entering a target array
    if (state === 'none') {
      if (/^\s*controversies:\s*\[/.test(line)) {
        state = 'controversies';
        bracketDepth = 1;
        outLines.push(line);
        // Check if array closes on same line
        if (trimmed.endsWith('],') || trimmed.endsWith(']')) {
          state = 'none';
        }
        continue;
      }
      if (/^\s*timeline:\s*\[/.test(line)) {
        state = 'timeline';
        bracketDepth = 1;
        outLines.push(line);
        if (trimmed.endsWith('],') || trimmed.endsWith(']')) {
          state = 'none';
        }
        continue;
      }
      if (/^\s*sources:\s*\[/.test(line)) {
        state = 'sources';
        bracketDepth = 1;
        outLines.push(line);
        if (trimmed.endsWith('],') || trimmed.endsWith(']')) {
          state = 'none';
        }
        continue;
      }
      if (/^\s*crimeDossier:\s*\[/.test(line)) {
        state = 'crimeDossier';
        bracketDepth = 1;
        outLines.push(line);
        if (trimmed.endsWith('],') || trimmed.endsWith(']')) {
          state = 'none';
        }
        continue;
      }
      outLines.push(line);
      continue;
    }

    // Inside a target array
    // Check for array close: just '],' or ']' 
    if (trimmed === '],' || trimmed === ']') {
      // Flush any pending object
      if (inObject && currentObjectLines.length > 0) {
        // Keep it (it wasn't matched for removal)
        outLines.push(...currentObjectLines);
        currentObjectLines = [];
        inObject = false;
      }
      state = 'none';
      outLines.push(line);
      continue;
    }

    // Determine which marker set to use
    let markers;
    switch (state) {
      case 'controversies': markers = FAKE_CONTROVERSY_SUBS; break;
      case 'timeline': markers = FAKE_TIMELINE_SUBS; break;
      case 'sources': markers = FAKE_SOURCE_SUBS; break;
      case 'crimeDossier': markers = FAKE_DOSSIER_SUBS; break;
    }

    // controversies are string entries (single line or multi-line strings)
    if (state === 'controversies') {
      // A controversy entry is typically a full string on one line: 'text text text',
      if (isFake(line, markers)) {
        removed.controversies++;
        continue; // skip this line
      }
      outLines.push(line);
      continue;
    }

    // timeline / sources / crimeDossier are object entries: { ... }
    // They can be single-line or multi-line
    if (state === 'timeline' || state === 'sources' || state === 'crimeDossier') {
      // Check if this is a single-line object entry
      if (trimmed.startsWith('{') && (trimmed.endsWith('},') || trimmed.endsWith('}'))) {
        // Single-line object
        if (isFake(line, markers)) {
          if (state === 'timeline') removed.timeline++;
          else if (state === 'sources') removed.sources++;
          else removed.dossier++;
          continue;
        }
        outLines.push(line);
        continue;
      }

      // Multi-line object start
      if (trimmed.startsWith('{') && !trimmed.endsWith('},') && !trimmed.endsWith('}')) {
        inObject = true;
        currentObjectLines = [line];
        continue;
      }

      // Multi-line object continuation
      if (inObject) {
        currentObjectLines.push(line);
        if (trimmed.endsWith('},') || trimmed === '},' || trimmed === '}') {
          // Object complete - check if fake
          const combined = currentObjectLines.join(' ');
          if (isFake(combined, markers)) {
            if (state === 'timeline') removed.timeline++;
            else if (state === 'sources') removed.sources++;
            else removed.dossier++;
          } else {
            outLines.push(...currentObjectLines);
          }
          currentObjectLines = [];
          inObject = false;
        }
        continue;
      }

      // Blank or empty lines inside array
      if (trimmed === '' || trimmed === ',') {
        outLines.push(line);
        continue;
      }

      // String entries in source/timeline array (shouldn't happen but keep)
      if (isFake(line, markers)) {
        if (state === 'timeline') removed.timeline++;
        else if (state === 'sources') removed.sources++;
        else removed.dossier++;
        continue;
      }
      outLines.push(line);
      continue;
    }
  }

  const totalRemoved = removed.controversies + removed.timeline + removed.sources + removed.dossier;
  
  if (totalRemoved > 0) {
    fs.writeFileSync(filePath, outLines.join('\n'), 'utf-8');
  }

  return removed;
}

// ── Main ────────────────────────────────────────────────────────────────────
console.log('=== ArkHive Fake Entry Stripping ===\n');

const files = fs.readdirSync(INDIVIDUALS_DIR)
  .filter(f => f.endsWith('.ts') && f !== 'types.ts' && f !== 'index.ts')
  .sort();

let totalC = 0, totalT = 0, totalS = 0, totalD = 0;

for (const file of files) {
  const filePath = path.join(INDIVIDUALS_DIR, file);
  const r = processFile(filePath);
  totalC += r.controversies;
  totalT += r.timeline;
  totalS += r.sources;
  totalD += r.dossier;
  
  const sum = r.controversies + r.timeline + r.sources + r.dossier;
  if (sum > 0) {
    console.log(`${file}: -${r.controversies} contros, -${r.timeline} timeline, -${r.sources} sources, -${r.dossier} dossier`);
  }
}

const total = totalC + totalT + totalS + totalD;
console.log(`\n=== Summary ===`);
console.log(`Files processed: ${files.length}`);
console.log(`Controversies removed: ${totalC}`);
console.log(`Timeline entries removed: ${totalT}`);
console.log(`Source entries removed: ${totalS}`);
console.log(`Dossier entries removed: ${totalD}`);
console.log(`TOTAL fake entries removed: ${total}`);
